VALUES ('3cd40446-0746-4e8b-ac71-5da2815aa366', 'Which choice completes the text so that it conforms to the conventions of Standard English?', 'Punctuation does quiet but decisive work at the seams of a sentence, signaling whether two ideas should be read as independent statements, as a cause joined to its effect, or as a main clause trailed by an explanatory aside; editors weigh these options carefully, and the sentence that follows presents exactly such a choice. The committee approved only one of the three proposals ______ the one that promised measurable results within a single fiscal year ______ and rejected the rest as too speculative.', 'passage', '[{"id":"A","text":"— ... —","is_correct":true,"explanation":"Correct (A). Matched em dashes set off the appositive."},{"id":"B","text":": ... :","is_correct":false,"explanation":"[Comma Splice] Colons cannot wrap a mid-clause appositive."},{"id":"C","text":", ... ;","is_correct":false,"explanation":"[Run-on Conjunction] Comma-semicolon pairing is unmatched."},{"id":"D","text":"— ... ,","is_correct":false,"explanation":"[Fragmented Semicolon/Colon] Dash-comma pairing is unmatched."}]'::jsonb, 'A', 'Step 1 — Locate clause boundaries
Focus on {{yellow:trailed}} in the passage. The boundaries item asks you to locate clause boundaries before comparing choices.

Step 2 — Apply punctuation rules
Compare each option against explicit textual evidence. On hard items, correct answers usually restate the passage faithfully without absolute words the text does not support.

Step 3 — Select the correct boundary
Choice A is correct: — ... —.

Distractor analysis:
- B: [Comma Splice] Colons cannot wrap a mid-clause appositive.
- C: [Run-on Conjunction] Comma-semicolon pairing is unmatched.
- D: [Fragmented Semicolon/Colon] Dash-comma pairing is unmatched.', NULL, 'Standard English Conventions', 'Boundaries', 'reading_writing', 'conventions', 'BOU', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"dsat_blueprint_v1":true,"rw_subtype":"boundaries","rw_format":"grammar_blank","generator":"regenerate-english-fresh.mjs","regen_seed_offset":100000,"explanation_v2":true}'::jsonb, now(), now());
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2da8898e-023d-4a45-ac1f-bb67e92ad3ac', 'Which choice completes the text so that it conforms to the conventions of Standard English?', 'Readers rarely notice punctuation when it is handled well, yet the placement of a single semicolon or colon can determine whether a sentence reads as two balanced clauses, as a claim followed by its evidence, or as a fragment; the example that follows asks which mark best fits the intended relationship. Throughout the late Mesozoic era, angiosperms (flowering plants) underwent a rapid diversification that fundamentally restructured terrestrial ______ ancient gymnosperms like conifers and cycads, which had dominated landscapes for millions of years, were quickly relegated to marginal ecological niches.', 'passage', '[{"id":"A","text":"ecosystems,","is_correct":false,"explanation":"[Comma Splice] Comma splice between independent clauses."},{"id":"B","text":"ecosystems; while","is_correct":false,"explanation":"[Run-on Conjunction] ''while'' after semicolon creates a fragment."},{"id":"C","text":"ecosystems—","is_correct":true,"explanation":"Correct (C). Em dash introduces explanatory elaboration of the restructuring."},{"id":"D","text":"ecosystems, and","is_correct":false,"explanation":"[Fragmented Semicolon/Colon] Treats clauses as parallel actions rather than explanation."}]'::jsonb, 'C', 'Step 1 — Locate clause boundaries
Focus on {{yellow:example}} in the passage. The boundaries item asks you to locate clause boundaries before comparing choices.

Step 2 — Apply punctuation rules
Compare each option against explicit textual evidence. On hard items, correct answers usually restate the passage faithfully without absolute words the text does not support.

Step 3 — Select the correct boundary
Choice C is correct: ecosystems—.

Distractor analysis:
- A: [Comma Splice] Comma splice between independent clauses.
- B: [Run-on Conjunction] ''while'' after semicolon creates a fragment.
- D: [Fragmented Semicolon/Colon] Treats clauses as parallel actions rather than explanation.', NULL, 'Standard English Conventions', 'Boundaries', 'reading_writing', 'conventions', 'BOU', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"dsat_blueprint_v1":true,"rw_subtype":"boundaries","rw_format":"grammar_blank","generator":"regenerate-english-fresh.mjs","regen_seed_offset":100000,"explanation_v2":true}'::jsonb, now(), now());
